61	// ====== 3. HELPER FUNCTIONS ======
62	
63	// 提取品类名：取最后一个*后面的内容
64	function extractCategory(name) {
65	    if (!name) return '';
66	    const s = name.toString().trim();
67	    if (!s) return '';
68	    const parts = s.split('*');
69	    return parts[parts.length - 1].trim();
70	}
71	
72	// 判断是否应该被过滤掉
73	function shouldFilter(name, cat) {
74	    if (!name && !cat) return true;
75	    const check = [name.toString(), cat].filter(Boolean);
76	    return check.some(c => filterList.some(f => c.includes(f)));
77	}
