177	// ====== 4. EXTRACT AND PARSE ALL DATA ======
178	
179	// 列索引：L=11, M=12, N=13, O=14, P=15
180	const COL = { name: 11, spec: 12, unit: 13, qty: 14, price: 15, invoiceNo: 3, date: 8, buyer: 7, seller: 5, note: 26 };
