182	function parseRows(rows, source) {
183	    const result = [];
184	    for (let i = 1; i < rows.length; i++) {
185	        const row = rows[i];
186	        const rawName = row[COL.name] ? row[COL.name].toString().trim() : '';
187	        if (!rawName) continue;
188	
189	        const category = extractCategory(rawName);
190	        if (!category || shouldFilter(rawName, category)) continue;
191	
192	        const spec = row[COL.spec] ? row[COL.spec].toString().trim() : '';
193	        const origUnit = row[COL.unit] ? row[COL.unit].toString().trim() : '';
194	        const rawQty = parseFloat(row[COL.qty]) || 0;
195	        const rawPrice = parseFloat(row[COL.price]) || 0;
196	        const invoiceNo = row[COL.invoiceNo] ? row[COL.invoiceNo].toString().trim() : '';
197	        const date = row[COL.date] ? row[COL.date].toString().trim() : '';
198	        const note = row[COL.note] ? row[COL.note].toString().trim() : '';
199	
200	        // 单位换算
201	        const conv = convertUnit(category, spec, origUnit, rawQty);
202	
203	        // 找标准关键词
204	        const keyword = getStandardKeyword(category);
205	
206	        result.push({
207	            rowNum: i,
208	            source,
209	            rawName,
210	            category,
211	            keyword,
212	            spec,
213	            origUnit,
214	            unit: conv.unit,
215	            origQty: rawQty,
216	            qty: conv.qty,
217	            price: rawPrice,
218	            convRate: conv.rate || 1,
219	            converted: conv.converted,
220	            invoiceNo,
221	            date,
222	            note
223	        });
224	    }
225	    return result;
226	}
