322	// 将未匹配的产品各自单独成组
323	for (const c of unmatchedJin) {
324	    const gid = groups.length + 1;
325	    catToGroup.set(c, gid);
326	    groups.push({ id: gid, jinNames: new Set([c]), xiaoNames: new Set() });
327	}
328	for (const c of unmatchedXiao) {
329	    const gid = groups.length + 1;
330	    catToGroup.set(c, gid);
331	    groups.push({ id: gid, jinNames: new Set(), xiaoNames: new Set([c]) });
332	}
333	
334	// 为每行数据分配组ID
335	for (const d of jinData) d.groupId = catToGroup.get(d.category) || 0;
336	for (const d of xiaoData) d.groupId = catToGroup.get(d.category) || 0;
