340	// --- Sheet 1: 数量汇总对比 ---
341	// 每个产品组+单位对比数量
342	function buildQtyComparison(groups, jinData, xiaoData) {
343	    const rows = [];
344	
345	    for (const g of groups) {
346	        // 用进项+销项所有出现过的单位
347	        const jinUnits = new Map(); // unit → totalQty
348	        const xiaoUnits = new Map(); // unit → totalQty
349	
350	        const gJinData = jinData.filter(d => d.groupId === g.id);
351	        const gXiaoData = xiaoData.filter(d => d.groupId === g.id);
352	
353	        for (const d of gJinData) {
354	            jinUnits.set(d.unit, (jinUnits.get(d.unit) || 0) + d.qty);
355	        }
356	        for (const d of gXiaoData) {
357	            xiaoUnits.set(d.unit, (xiaoUnits.get(d.unit) || 0) + d.qty);
358	        }
359	
360	        // 进项名称和销项名称展示
361	        const jinNames = [...g.jinNames].join('; ');
362	        const xiaoNames = [...g.xiaoNames].join('; ');
363	
364	        // 所有涉及的单位
365	        const allUnits = new Set([...jinUnits.keys(), ...xiaoUnits.keys()]);
366	
367	        for (const unit of allUnits) {
368	            const jinQty = jinUnits.get(unit) || 0;
369	            const xiaoQty = xiaoUnits.get(unit) || 0;
370	            const diff = jinQty - xiaoQty;
371	            rows.push({
372	                产品组编号: g.id,
373	                进项品类: jinNames || '—',
374	                销项品类: xiaoNames || '—',
375	                单位: unit,
376	                进项总数量: Math.round(jinQty * 100) / 100,
377	                销项总数量: Math.round(xiaoQty * 100) / 100,
378	                数量差异: Math.round(diff * 100) / 100,
379	                说明: jinQty > 0 && xiaoQty > 0 ? '' : (jinQty > 0 ? '仅有进项' : '仅有销项')
380	            });
381	        }
382	    }
383	    return rows;
384	}
