579	// 调整列宽
580	function autoColWidth(sheet, data) {
581	    if (!data || data.length === 0) return;
582	    const colWidths = {};
583	    const headers = Object.keys(data[0]);
584	    headers.forEach((h, i) => {
585	        colWidths[i] = Math.max(h.length * 2, 10);
586	    });
587	    data.forEach(row => {
588	        Object.values(row).forEach((val, i) => {
589	            const len = String(val).length * 2;
590	            if (len > colWidths[i]) colWidths[i] = Math.min(len, 80);
591	        });
592	    });
593	    sheet['!cols'] = Object.values(colWidths).map(w => ({ wch: w }));
594	}
